#include <bits/stdc++.h>
using namespace std;

const long long MOD = 1000000007;

long long solve(long long N, std::string S){
    map<char,int> ma;
    for(int i=0;i<N;++i){
        ma[S[i]]++;
    }
    long long res = 1;
    for(auto p:ma){
        res *= p.second + 1;
        res %= MOD;
    }
    return ((res-1)%MOD+MOD)%MOD;
}

// Generated by 1.1.3 https://github.com/kyuridenamida/atcoder-tools  (tips: You use the default template now. You can remove this line by using your custom template)
int main(){
    long long N;
    scanf("%lld",&N);
    std::string S;
    std::cin >> S;
    cout<<solve(N, S)<<endl;
    return 0;
}
